// 枚举所有 mask 的子集（包括空集和自身）
for (int mask = 0; mask < (1 << n); mask++) {
    // 枚举 mask 的所有子集 sub
    for (int sub = mask; ; sub = (sub - 1) & mask) {
		// 处理 sub 子集

      	if (sub == 0) break;
    }
}

// 枚举所有 mask 的超集（包括自身）
for (int mask = 0; mask < (1 << n); mask++) {
    // 做法是枚举补集的子集
    int comp = ((1 << n) - 1) ^ mask; // 补集
    for (int sub = comp; ; sub = (sub - 1) & comp) {
        int sup = mask | sub;  // sup 是 mask 的超集
        // 处理超集 sup

        if (sub == 0) break;
    }
}

void dfs(int sub) {
    // 已处理过 sub 和它的子集们，剪枝
    if (vis[sub]) return;
    vis[sub] = true;

    // 处理子集 sub

    // 递归遍历直接子集 (去掉 1 个 bit)
    for (int i = 0; i < MAX_BITS; ++i) 
      	// 去掉第 i 位的 1，变成子集，递归下去
        if (sub & (1 << i))    
            dfs(sub ^ (1 << i));
}

void dfs(int sup) {
    // 已处理过 sup 和它的超集们，剪枝
    if (vis[sup]) return;
    vis[sub] = true;

    // 处理超集 sup

    // 递归遍历直接超集 (加上 1 个 bit)
    for (int i = 0; i < MAX_BITS; ++i) 
   		// 如果 mask 的第 i 位是 0，我们可以把它变成 1 构成超集
        if (!(sup & (1 << i))) 
            dfs(sup ^ (1 << i));
}
